function pad2(n) {
  return String(n).padStart(2, '0');
}

function todayISO() {
  return new Date().toISOString().slice(0, 10);
}

function excelSerialToISO(n) {
  const excelEpoch = Date.UTC(1899, 11, 30);
  const ms = excelEpoch + Number(n) * 86400000;
  const d = new Date(ms);
  return isNaN(d.getTime()) ? null : d.toISOString().slice(0, 10);
}

function parseDateToISO(v) {
  if (v === null || v === undefined || v === '') return null;

  if (typeof v === 'number') return excelSerialToISO(v);

  const s = String(v).trim();
  if (!s) return null;

  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);

  const m = s.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{4})$/);
  if (m) return `${m[3]}-${pad2(m[2])}-${pad2(m[1])}`;

  const d = new Date(s);
  return isNaN(d.getTime()) ? null : d.toISOString().slice(0, 10);
}

function toASCII(domain) {
  if (!domain) return null;

  let d = String(domain)
    .normalize('NFC')
    .trim()
    .replace(/^[a-z]+:\/\//i, '')   // remove protocol
    .replace(/[/?#].*$/, '')        // remove path/query/hash
    .replace(/:\d+$/, '')           // remove port
    .replace(/\.+$/, '')            // remove trailing dots
    .toLowerCase();

  try {
    const urlMod = require('node:url');
    if (typeof urlMod.domainToASCII === 'function') {
      const ascii = urlMod.domainToASCII(d);
      return ascii || null;
    }
  } catch (e) {}

  return d;
}

function cleanDomain(value) {
  if (value === null || value === undefined || value === '') return null;

  let d = String(value)
    .normalize('NFC')
    .trim()
    .replace(/\s+/g, '')            // remove all spaces
    .replace(/\u3002|\uFF0E|\uFF61/g, '.') // normalize unicode dots
    .replace(/\.+$/, '')            // remove trailing dots
    .toLowerCase();

  d = toASCII(d);

  if (!d || !d.includes('.')) return null;

  // reject obvious bad leftovers
  if (/[^\x20-\x7E]/.test(d)) return null;

  return d;
}

function cleanText(value) {
  if (value === null || value === undefined || value === '') return null;
  const s = String(value).trim();
  return s || null;
}

function cleanDomainType(value) {
  if (value === null || value === undefined || value === '') return null;

  const s = String(value).trim().toLowerCase();

  if (['renew', 'renewal'].includes(s)) return 'renew';
  if (['new', 'registration', 'create'].includes(s)) return 'new';
  if (['premium new', 'premium_new', 'premiumnew'].includes(s)) return 'premium new';
  if (['premium renew', 'premium_renew', 'premiumrenew'].includes(s)) return 'premium renew';

  return s;
}

const allItems = $input.all();
const firstRow = allItems[0]?.json || {};
const fileFallbackDate = parseDateToISO(firstRow.file_date) || todayISO();

const seen = new Set();
const output = [];

for (const item of allItems) {
  const row = item.json || {};

  const cleanedDomain = cleanDomain(row.domain);
  if (!cleanedDomain) continue;

  if (seen.has(cleanedDomain)) continue;
  seen.add(cleanedDomain);

  let finalDate = parseDateToISO(row.date);
  if (!finalDate) finalDate = fileFallbackDate;

  output.push({
    json: {
      date: finalDate,
      domain: cleanedDomain,
      domain_type: cleanDomainType(row.domain_type),
      client: cleanText(row.client),
      promo_tag: cleanText(row.promo_tag)
    }
  });
}

return output;

function cleanString(v) {
  if (v === undefined || v === null) return null;
  const s = String(v).trim();
  return s === "" ? null : s;
}

function normalizeDate(v) {
  if (v === undefined || v === null) return null; 
  const s = String(v).trim();
  if (!s) return null;

  if (/^\d{4}-\d{2}-\d{2}$/.test(s)) return s;
  if (/^\d{4}-\d{2}-\d{2}T/.test(s)) return s.slice(0, 10);

  return null;
}

// ✅ safest: read filename from the Split Out node (1 file → many rows)
const filename = $items("Get a list of objects")[0]?.json?.name || null;

return {
  client: cleanString($json.client),
  date: normalizeDate($json.date),
  domain: cleanString($json.domain),
  domain_type: cleanString($json.domain_type),
  promo_tag: cleanString($json.promo_tag),
  file_name: cleanString(filename),
};

