TRUNCATE TABLE `radixbi-249015.rebate_process_temp.rebate_cleaned_data`;

INSERT INTO `radixbi-249015.rebate_process_temp.rebate_cleaned_data`
(client, date, domain, domain_type, promo_tag, file_name)
VALUES
{{ 
  $items("data ready for insert").map(i => {
    const r = i.json;

    const esc = (v) => String(v).replace(/\\/g, "\\\\").replace(/'/g, "\\'");
    const s = (v) => (v === null || v === undefined || v === '') ? 'NULL' : `'${esc(v)}'`;
    const d = (v) => (v === null || v === undefined || v === '') ? 'NULL' : `DATE '${esc(v)}'`;

    return `(${s(r.client)}, ${d(r.date)}, ${s(r.domain)}, ${s(r.domain_type)}, ${s(r.promo_tag)}, ${s(r.file_name)})`;
  }).join(",\n")
}}
;
UPDATE `radixbi-249015.rebate_process_temp.rebate_cleaned_data`
SET tld =
CASE
  WHEN LOWER(domain) LIKE '%.in.net' THEN 'in.net'
  WHEN LOWER(domain) LIKE '%.co.in' THEN 'co.in'
  ELSE LOWER(REGEXP_EXTRACT(domain, r'([^.]+)$'))
END
WHERE tld IS NULL;
